UPDATE wms_inbound_order
order_type = #{orderType}, supplier_id = #{supplierId}, warehouse_id = #{warehouseId}, status = #{status}, inbound_date = #{inboundDate}, complete_date = #{completeDate}, total_qty = #{totalQty}, total_amount = #{totalAmount}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
