material_id = #{materialId}, plan_qty = #{planQty}, received_qty = #{receivedQty}, putaway_qty = #{putawayQty}, batch_no = #{batchNo}, production_date = #{productionDate}, expiry_date = #{expiryDate}, location_id = #{locationId}, unit_price = #{unitPrice}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
